# Quantization mapping simulation
def quantize_vector(vector, sub_spaces=8, centroids_per_subspace=256):
    # Split 1536-dim vector into 8 sub-vectors of 192 dimensions
    sub_vectors = np.split(vector, sub_spaces)
    quantized_codes = []
    for sv in sub_vectors:
        # Map sub-vector to the nearest centroid index (0-255)
        centroid_idx = find_nearest_centroid(sv)
        quantized_codes.append(centroid_idx)
    return np.array(quantized_codes, dtype=np.uint8)

def reciprocal_rank_fusion(dense_ranks, sparse_ranks, k=60):
    rrf_scores = {}
    all_docs = set(dense_ranks.keys()).union(set(sparse_ranks.keys()))
    for doc in all_docs:
        # Rank is 1-indexed; default to large rank if document is missing in a split
        r_dense = dense_ranks.get(doc, 1000)
        r_sparse = sparse_ranks.get(doc, 1000)

        score = 1.0 / (k + r_dense) + 1.0 / (k + r_sparse)
        rrf_scores[doc] = score
    return rrf_scores
